                            {processing ? 'Starting Match...' : 'START MATCH'}
                        </button>
                    </div>
                </div>
            )}

            {/* 1. Header Match Scoreboard */}
            <div className="bg-white p-4 shadow-sm border-b sticky top-0 z-10">
                <div className="flex justify-between items-center mb-2">
